import{_ as t,o,c as a,ag as n}from"./chunks/framework.DFmy_ALI.js";const p=JSON.parse('{"title":"Merchant Postman Project","description":"","frontmatter":{},"headers":[],"relativePath":"guide/merchant-postman-project.md","filePath":"guide/merchant-postman-project.md"}'),i={name:"guide/merchant-postman-project.md"};function r(d,e,c,l,s,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="merchant-postman-project" tabindex="-1">Merchant Postman Project <a class="header-anchor" href="#merchant-postman-project" aria-label="Permalink to &quot;Merchant Postman Project&quot;">​</a></h1><p>Use this project when a merchant team wants a runnable Postman workspace instead of piecing together raw OpenAPI files. It covers the merchant surfaces that matter in Astro:</p><ul><li>hosted checkout via Merchant API</li><li>trusted merchant-hosted checkout</li><li>webhook setup and replay</li><li>reports and readiness</li><li>recurring mandates</li><li>presented payments</li><li>open banking</li><li>credit and finance</li></ul><p>This is for merchant backends, QA, operations, and partner enablement. It is not a browser-side integration artifact.</p><h2 id="downloads" tabindex="-1">Downloads <a class="header-anchor" href="#downloads" aria-label="Permalink to &quot;Downloads&quot;">​</a></h2><ul><li><a href="/astro-sdk/astro-sdk/postman/neptune-astro-merchant-suite.postman_collection.json">Merchant suite collection</a></li><li><a href="/astro-sdk/astro-sdk/postman/neptune-astro-sandbox.postman_environment.json">Sandbox environment</a></li><li><a href="/astro-sdk/astro-sdk/postman/neptune-astro-live.postman_environment.json">Live environment</a></li></ul><h2 id="what-this-collection-includes" tabindex="-1">What this collection includes <a class="header-anchor" href="#what-this-collection-includes" aria-label="Permalink to &quot;What this collection includes&quot;">​</a></h2><p>The collection is organized as a real runbook:</p><ol><li><code>01 Public and Merchant Baseline</code></li><li><code>02 Hosted Checkout via Merchant API</code></li><li><code>03 Trusted Merchant-Hosted Checkout</code></li><li><code>04 Merchant Webhooks and Recovery</code></li><li><code>05 Merchant Reports and Readiness</code></li><li><code>06 Recurring Mandates</code></li><li><code>07 Presented Payments</code></li><li><code>08 Open Banking</code></li><li><code>09 Credit and Finance</code></li></ol><p>Requests capture IDs and tokens into collection variables so the next step can run without manual copy/paste.</p><h2 id="recommended-run-order" tabindex="-1">Recommended run order <a class="header-anchor" href="#recommended-run-order" aria-label="Permalink to &quot;Recommended run order&quot;">​</a></h2><h3 id="standard-merchant-checkout" tabindex="-1">Standard merchant checkout <a class="header-anchor" href="#standard-merchant-checkout" aria-label="Permalink to &quot;Standard merchant checkout&quot;">​</a></h3><ol><li>Import the collection.</li><li>Import the sandbox or live environment.</li><li>Fill in <code>merchant_api_key</code>, <code>redirect_url</code>, <code>cancel_url</code>, and <code>merchant_webhook_url</code>.</li><li>Run <code>02 Hosted Checkout via Merchant API -&gt; Create Hosted Payment Session</code>.</li><li>Open the returned <code>payment_url</code> if you want the OpenWave-hosted customer flow.</li><li>Use <code>Get Payment Session</code>, webhook logs, and reports to verify completion.</li></ol><h3 id="trusted-merchant-hosted-checkout" tabindex="-1">Trusted merchant-hosted checkout <a class="header-anchor" href="#trusted-merchant-hosted-checkout" aria-label="Permalink to &quot;Trusted merchant-hosted checkout&quot;">​</a></h3><p>This path is for approved merchants only. It keeps the customer fully inside the merchant website or app.</p><ol><li>Use a merchant key with trusted checkout enabled.</li><li>Run <code>03 Trusted Merchant-Hosted Checkout -&gt; Create Trusted Merchant-Hosted Session</code>.</li><li>Run <code>Exchange Merchant-Hosted Access Token</code>.</li><li>Continue with one payer path: <ul><li><code>Resolve Payer by Alias</code></li><li><code>Resolve Payer by IBAN</code></li><li>phone flow: <code>Phone Start</code>, <code>Phone Verify</code>, <code>Phone Select</code></li></ul></li><li>Run <code>Select Auth Method</code>.</li><li>If the bank returned OTP, run <code>Confirm OTP</code>.</li><li>If the bank returned push, poll <code>Get Push Status</code>.</li><li>Always finish with webhook-backed verification and <code>Get Trusted Checkout Status</code>.</li></ol><h3 id="open-banking" tabindex="-1">Open banking <a class="header-anchor" href="#open-banking" aria-label="Permalink to &quot;Open banking&quot;">​</a></h3><ol><li>Fill in <code>tpp_client_id</code> and <code>tpp_client_secret</code>.</li><li>Use a real PKCE challenge and verifier pair.</li><li>Run the <code>08 Open Banking</code> folder in order.</li><li>After token exchange, the account and payment order requests use the captured bearer token automatically.</li></ol><h2 id="variables-you-must-set" tabindex="-1">Variables you must set <a class="header-anchor" href="#variables-you-must-set" aria-label="Permalink to &quot;Variables you must set&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Required for</th><th>Notes</th></tr></thead><tbody><tr><td><code>merchant_api_key</code></td><td>All merchant payment, webhook, report, mandate, presentment, and finance calls</td><td>Use <code>mk_test_...</code> in sandbox and <code>mk_live_...</code> in live.</td></tr><tr><td><code>tpp_client_id</code> / <code>tpp_client_secret</code></td><td>Open banking consent and token exchange</td><td>Server-to-server only.</td></tr><tr><td><code>redirect_url</code></td><td>Hosted checkout, open banking, finance offers</td><td>Must match the merchant allow-list where applicable.</td></tr><tr><td><code>merchant_webhook_url</code></td><td>Webhook endpoint setup</td><td>Use an HTTPS receiver you control.</td></tr><tr><td><code>allowed_origin</code></td><td>Trusted merchant-hosted checkout</td><td>Must be approved on the merchant profile for browser-side trusted checkout.</td></tr><tr><td><code>payer_alias</code>, <code>payer_iban</code>, <code>payer_phone</code></td><td>Customer simulation</td><td>In live, use real enrolled identifiers.</td></tr><tr><td><code>otp_code</code></td><td>OTP confirmation requests</td><td>Leave blank in live until the customer receives it.</td></tr></tbody></table><h2 id="security-boundary" tabindex="-1">Security boundary <a class="header-anchor" href="#security-boundary" aria-label="Permalink to &quot;Security boundary&quot;">​</a></h2><p>Keep the split clear:</p><ul><li>merchant API keys stay on the merchant backend</li><li><code>/merchant-checkout/access</code> is backend-only</li><li><code>X-Session-Token</code> is short-lived and scoped to one trusted checkout session</li><li>fulfilment must wait for the signed final webhook such as <code>payment.completed</code></li><li>do not store raw OTP values after submission</li></ul><h2 id="live-testing-notes" tabindex="-1">Live testing notes <a class="header-anchor" href="#live-testing-notes" aria-label="Permalink to &quot;Live testing notes&quot;">​</a></h2><p>Live testing is not just a different URL. It requires:</p><ul><li>live merchant key or live channel key</li><li>live enablement on the merchant profile</li><li>approved settlement routing</li><li>active webhook endpoint</li><li>trusted merchant-hosted approval if that flow is being used</li></ul><p>For live alias, IBAN, and phone tests, replace the placeholder values in the live environment with real merchant-approved production data. Public docs do not ship live customer fixtures.</p><h2 id="related-guides" tabindex="-1">Related guides <a class="header-anchor" href="#related-guides" aria-label="Permalink to &quot;Related guides&quot;">​</a></h2><ul><li><a href="./ezone-quickstart.html">Ezone Quick Start</a></li><li><a href="./direct-integration.html">Direct Integration</a></li><li><a href="./trusted-merchant-hosted.html">Trusted Merchant-Hosted Checkout</a></li><li><a href="./webhooks.html">Webhooks</a></li><li><a href="./merchant-operations.html">Merchant Operations</a></li></ul>',29)])])}const m=t(i,[["render",r]]);export{p as __pageData,m as default};
